const context = $('Build AI Context').first().json || {};
const output = String(($input.first().json || {}).output || '').trim();

function parseJson(text) {
  try { return JSON.parse(text); } catch { return null; }
}
function extractJson(text) {
  if (!text) return null;
  const direct = parseJson(text);
  if (direct) return direct;
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced) {
    const parsed = parseJson(fenced[1].trim());
    if (parsed) return parsed;
  }
  const first = text.indexOf('{');
  const last = text.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    return parseJson(text.slice(first, last + 1));
  }
  return null;
}

function clean(value) { return String(value ?? '').trim(); }
function parseBool(value) {
  if (typeof value === 'boolean') return value;
  const s = clean(value).toLowerCase();
  if (['true','yes','y','1','done'].includes(s)) return true;
  if (['false','no','n','0','skip','skipped'].includes(s)) return false;
  return null;
}
function normalizeIsoDate(value, fallback = null) {
  const s = clean(value);
  if (!s) return fallback;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const us = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (us) return `${us[3]}-${String(us[1]).padStart(2, '0')}-${String(us[2]).padStart(2, '0')}`;
  if (/^today$/i.test(s)) return context.today_bkk || fallback;
  if (/^tomorrow$/i.test(s)) return $now.setZone('Asia/Bangkok').plus({ days: 1 }).toFormat('yyyy-MM-dd');
  if (/^yesterday$/i.test(s)) return $now.setZone('Asia/Bangkok').minus({ days: 1 }).toFormat('yyyy-MM-dd');
  return fallback;
}
function normalizeLoose(value) {
  return clean(value)
    .replace(/[^\p{L}\p{N}\s]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}
const statusMap = new Map([
  ['completed', '✅ Completed'],
  ['done', '✅ Completed'],
  ['complete', '✅ Completed'],
  ['in progress', '🔄 In Progress'],
  ['progress', '🔄 In Progress'],
  ['pending', '⏳ Pending'],
  ['on hold', '✋ On Hold'],
  ['hold', '✋ On Hold'],
  ['delayed', '🛑 Delayed'],
  ['overdue', '⚠️ Overdue'],
  ['under review', '🔍 Under Review'],
  ['review', '🔍 Under Review'],
  ['cancelled', '🚫 Canceled'],
  ['canceled', '🚫 Canceled'],
]);
function normalizeStatus(value) {
  const raw = clean(value);
  if (!raw) return '⏳ Pending';
  if ([...statusMap.values()].includes(raw)) return raw;
  return statusMap.get(normalizeLoose(raw)) || '⏳ Pending';
}
const priorityMap = new Map([
  ['high', '🟥 High'],
  ['medium', '🟪 Medium'],
  ['mid', '🟪 Medium'],
  ['low', '🟩 Low']
]);
function normalizePriority(value, important, urgent) {
  const raw = clean(value);
  if ([...priorityMap.values()].includes(raw)) return raw;
  const byText = priorityMap.get(normalizeLoose(raw));
  if (byText) return byText;
  if (important && urgent) return '🟥 High';
  if (important || urgent) return '🟪 Medium';
  return '🟩 Low';
}
const categoryMap = new Map([
  ['personal', '💖 Personal'],
  ['family', '👨‍👩‍👧‍👦 Family'],
  ['health', '🫁 Health'],
  ['career', '💻 Career '],
  ['finance', '💵 Finances'],
  ['finances', '💵 Finances'],
  ['household', '🏠 Household'],
  ['hobby', '🎨 Hobby'],
  ['travel', '✈️ Travel'],
  ['friends', '👯‍♀️ Friends'],
  ['appointment', '🗓 Appointment'],
  ['contact', '💌 Contact'],
  ['beauty', '💅 Beauty'],
  ['education', '📖 Education'],
  ['other', '⚡️ Chaos'],
  ['chaos', '⚡️ Chaos']
]);
function normalizeCategory(value) {
  const raw = clean(value);
  for (const v of categoryMap.values()) if (raw === v) return v;
  return categoryMap.get(normalizeLoose(raw)) || '⚡️ Chaos';
}
const trackMap = new Map([
  ['craft', '💪🏻 Craft'],
  ['vitality', '🫀 Vitality'],
  ['social', '🗣️ Social']
]);
const categoryTrackMap = new Map([
  ['💖 Personal', '🫀 Vitality'],
  ['🫁 Health', '🫀 Vitality'],
  ['🏠 Household', '🫀 Vitality'],
  ['💅 Beauty', '🫀 Vitality'],
  ['💻 Career ', '💪🏻 Craft'],
  ['💵 Finances', '💪🏻 Craft'],
  ['🎨 Hobby', '💪🏻 Craft'],
  ['📖 Education', '💪🏻 Craft'],
  ['✈️ Travel', '🗣️ Social'],
  ['👨‍👩‍👧‍👦 Family', '🗣️ Social'],
  ['👯‍♀️ Friends', '🗣️ Social'],
  ['🗓 Appointment', '🗣️ Social'],
  ['💌 Contact', '🗣️ Social'],
  ['⚡️ Chaos', '💪🏻 Craft']
]);
function normalizeTrack(value, category) {
  const raw = clean(value);
  for (const v of trackMap.values()) if (raw === v) return v;
  const byText = trackMap.get(normalizeLoose(raw));
  if (byText) return byText;
  return categoryTrackMap.get(category) || '💪🏻 Craft';
}
function computeXp(priority, task) {
  const explicit = Number(task.xp ?? task.xp_value ?? task['XP| HP'] ?? task.xp_hp);
  if (Number.isFinite(explicit) && explicit > 0) return explicit;
  if (priority === '🟥 High') return 30;
  if (priority === '🟪 Medium') return 20;
  return 10;
}
function pluralTasks(n) {
  if (n % 10 === 1 && n % 100 !== 11) return 'задачу';
  if ([2,3,4].includes(n % 10) && ![12,13,14].includes(n % 100)) return 'задачи';
  return 'задач';
}

const parsed = extractJson(output) || {};
const aiMode = clean(parsed.mode || context.mode).toUpperCase() || 'TASK_CAPTURE';
const tasksSource = Array.isArray(parsed.tasks)
  ? parsed.tasks
  : parsed.task
    ? [parsed.task]
    : [];

let needsClarification = !!parsed.needs_clarification;
const missingSlots = Array.isArray(parsed.missing_slots) ? parsed.missing_slots.filter(Boolean) : [];
const questions = Array.isArray(parsed.questions) ? parsed.questions.filter(Boolean) : [];

const taskRows = [];
for (const task of tasksSource) {
  const title = clean(task.title || task.task || task.name);
  if (!title) {
    needsClarification = true;
    if (!missingSlots.includes('title')) missingSlots.push('title');
    continue;
  }
  const recurring = parseBool(task.recurring) ?? false;
  const explicitImportant = parseBool(task.important);
  const explicitUrgent = parseBool(task.urgent);
  const category = normalizeCategory(task.category || task.category_hint);
  const priority = normalizePriority(task.priority, explicitImportant, explicitUrgent);
  const important = explicitImportant ?? (priority === '🟥 High');
  const urgent = explicitUrgent ?? false;
  const track = normalizeTrack(task.track || task.track_hint, category);
  const startDate = normalizeIsoDate(task.start_date, context.today_bkk || null);
  const dueDate = normalizeIsoDate(task.due_date, recurring ? null : startDate);
  const endDate = normalizeIsoDate(task.end_date, normalizeStatus(task.status) === '✅ Completed' ? (dueDate || startDate) : null);
  const frequency = recurring ? clean(task.frequency) || 'Every Week' : '';
  const notes = clean(task.notes || task.comment || task.time_block);
  taskRows.push({
    task: title,
    xp_value: computeXp(priority, task),
    recurring,
    frequency,
    start_date: startDate,
    end_date: endDate,
    due_date: dueDate,
    status: normalizeStatus(task.status),
    category,
    priority,
    track,
    important,
    urgent,
    notes
  });
}

const hasTasks = !needsClarification && taskRows.length > 0;

const goalWrites = [];
const goalGameLogRows = [];
if (!needsClarification && aiMode === 'GOAL_DECOMPOSER') {
  const steps = Array.isArray(parsed.steps) ? parsed.steps.map(item => clean(item)).filter(Boolean).slice(0, 10) : [];
  const goalSlot = Number(context.goal_slot || 1);
  if (!steps.length) {
    needsClarification = true;
    if (!missingSlots.includes('steps')) missingSlots.push('steps');
  } else {
    const textCols = ['G','L','Q','V','AA','AF','AK','AP','AU','AZ'];
    const checkboxCols = ['F','K','P','U','Z','AE','AJ','AO','AT','AY'];
    const deadlineCols = ['H','M','R','W','AB','AG','AL','AQ','AV','BA'];
    const slotIndex = Math.max(0, Math.min(9, goalSlot - 1));
    const textCol = textCols[slotIndex];
    const checkboxCol = checkboxCols[slotIndex];
    const deadlineCol = deadlineCols[slotIndex];
    const textValues = [];
    for (let row = 17; row <= 35; row++) {
      const stepIndex = Math.floor((row - 17) / 2);
      const isOddTarget = row % 2 === 1;
      textValues.push([isOddTarget ? (steps[stepIndex] || '') : '']);
    }
    const checkboxValues = [];
    for (let row = 17; row <= 35; row++) {
      checkboxValues.push([row % 2 === 1 ? false : '']);
    }
    goalWrites.push({ range: `PROFILE_GAME!${checkboxCol}17:${checkboxCol}35`, values: checkboxValues });
    goalWrites.push({ range: `PROFILE_GAME!${textCol}17:${textCol}35`, values: textValues });
    goalWrites.push({ range: `PROFILE_GAME!${deadlineCol}37`, values: [[normalizeIsoDate(parsed.shared_deadline || context.goal_deadline, '')]] });
    goalWrites.push({ range: `PROFILE_GAME!${deadlineCol}38`, values: [[clean(parsed.reward_suggestion || context.goal_reward)]] });
    const nowTs = $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd HH:mm:ss');
    const attemptId = clean(context.active_attempt_id || '');
    const levelName = clean(context.level_name || '');
    const stage = clean(context.player_stage || 'EARLY');
    goalGameLogRows.push([nowTs, 'GOAL_DECOMPOSED', 'QUEST_ARCHITECT', 'GOAL', String(goalSlot), clean(selectedGoal || parsed.goal_summary || context.selected_goal), '', 'UPDATED', String(steps.length), 'STEPS', '', '', context.today_bkk || $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd'), stage, levelName, attemptId, JSON.stringify({ goal_slot: goalSlot, steps, shared_deadline: normalizeIsoDate(parsed.shared_deadline || context.goal_deadline, ''), reward_suggestion: clean(parsed.reward_suggestion || context.goal_reward) }), 'Goal decomposition записан в PROFILE_GAME']);
  }
}

let responseText = clean(parsed.reply_hint);
if (needsClarification) {
  responseText = questions[0] || (missingSlots.length ? `Нужно уточнить: ${missingSlots.join(', ')}.` : 'Нужно чуть больше деталей.');
} else if (aiMode === 'GOAL_DECOMPOSER' && goalWrites.length) {
  const stepCount = (Array.isArray(parsed.steps) ? parsed.steps.filter(Boolean).length : 0) || 0;
  responseText = responseText || `Разложила цель на ${stepCount} шагов.`;
} else if (hasTasks) {
  responseText = responseText || `Подготовила ${taskRows.length} ${pluralTasks(taskRows.length)} к записи.`;
} else if (aiMode === 'PLANNER') {
  const focuses = Array.isArray(parsed.focuses) ? parsed.focuses.filter(Boolean).slice(0, 3) : [];
  const lines = [];
  if (focuses.length) lines.push(`Фокус дня: ${focuses.join(' • ')}`);
  if (questions[0]) lines.push(questions[0]);
  if (parsed.suggest_decomposition) lines.push('Если хочешь, могу сразу разложить цель на шаги.');
  responseText = responseText || lines.join('\n');
} else if (aiMode === 'EVENING_REVIEW') {
  const points = Array.isArray(parsed.review_points) ? parsed.review_points.filter(Boolean).slice(0, 3) : [];
  const lines = [];
  if (points.length) lines.push(`Вечерний фокус: ${points.join(' • ')}`);
  if (questions[0]) lines.push(questions[0]);
  responseText = responseText || lines.join('\n');
}

return [{
  json: {
    mode: aiMode,
    needs_clarification: needsClarification,
    missing_slots: missingSlots,
    questions,
    response_text: responseText || 'Сейчас не удалось собрать ответ Архитектора. Нужна еще одна попытка.',
    task_rows: taskRows,
    has_tasks: hasTasks,
    goal_writes: goalWrites,
    has_goal_writes: goalWrites.length > 0,
    goal_game_log_rows: goalGameLogRows,
    goal_slot: context.goal_slot || null,
    selected_goal: context.selected_goal || '',
    plan_date_hint: (taskRows[0] && (taskRows[0].due_date || taskRows[0].start_date)) || context.today_bkk || $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd')
  }
}];

