const trigger = $('Trigger').first().json || {};
const rawItemId = String(trigger.item_id || '').trim();
const count = Number(trigger.value) || 1;
const date = String(trigger.date || $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd'));
const status = String(trigger.status || 'DONE').trim().toUpperCase();
const aliasMap = {
  reading: 'read',
  read: 'read',
  game_chek: 'game_check',
  game_check: 'game_check',
  walk: 'walk',
  body_exercise: 'body_exercise',
  exercise: 'body_exercise',
  bad_plus: 'bad_plus',
  nad_plus: 'bad_plus',
  feet_exercise: 'feet_exercise',
  fiber_daily: 'fiber_daily',
  fiber: 'fiber_daily',
  math_mi: 'math_mi',
  thai_mi: 'thai_mi',
  antiparasitic: 'antiparasitic',
  water: 'water',
  client_search: 'client_search',
  post_content: 'post_content',
  posts: 'post_content',
  client_calls: 'client_calls',
  sales_calls: 'client_calls',
  youtube_video: 'youtube_video'
};
const active = (value) => {
  const s = String(value ?? '').trim().toLowerCase();
  return ['true', 'yes', '1'].includes(s) || value === true;
};
const rules = $('Read GAME_RULES (Quest)').all().map(i => i.json).filter(r => !String(r.ACTIVE || '').trim() || active(r.ACTIVE));
const mappedId = aliasMap[rawItemId] || rawItemId;
const rule = rules.find(r => String(r.ID_NAME || '').trim() === rawItemId)
  || rules.find(r => String(r.ID_NAME || '').trim() === mappedId)
  || {};
const canonicalId = String(rule.ID_NAME || '').trim() || mappedId;
const ruleValue = Number(rule.VALUE) || 0;
const resourceType = String(rule.RESOURCE_TYPE || 'XP_GOLD').trim() || 'XP_GOLD';
const track = String(rule.TRACK || 'GENERAL').trim() || 'GENERAL';
const rpgName = String(rule.RPG_NAME || rawItemId || canonicalId).trim();
const isDone = ['DONE', 'COMPLETED', 'TRUE'].includes(status);
const delta = isDone ? ruleValue * count : 0;
const ruleFound = !!rule.ID_NAME;
const eventType = isDone ? 'HABIT_DONE' : 'HABIT_SKIPPED';
const message = !ruleFound
  ? `⚠️ Не нашла правило привычки для ${rawItemId}. Ничего не записала.`
  : isDone
    ? `✅ ${rpgName} записано в GAME_LOG. ${delta ? `+${delta} ${resourceType}` : 'Без изменения ресурса.'}`
    : `⏭ ${rpgName} записано в GAME_LOG как пропуск.`;
const hpGainDelta = (isDone && (resourceType === 'HP' || track === 'VITALITY')) ? ruleValue * count : 0;
return [{ json: {
  raw_item_id: rawItemId,
  item_id: canonicalId,
  value: count,
  date,
  status: isDone ? 'DONE' : 'SKIPPED',
  is_done: isDone,
  delta,
  resource_type: resourceType,
  track,
  rpg_name: rpgName,
  event_type: eventType,
  message,
  rule_found: ruleFound,
  hp_gain_delta: hpGainDelta
} }];

const parsed = $('Parse Response').first().json || {};
const nowDate = $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd');
const candidate = String(parsed.plan_date_hint || nowDate).trim() || nowDate;
const plan_date = /^\d{4}-\d{2}-\d{2}$/.test(candidate) ? candidate : nowDate;
const sheet_name = plan_date.slice(2).replace(/-/g, '.');
const quoted_sheet_name = `'${sheet_name.replace(/'/g, "''")}'`;
return [{ json: { plan_date, sheet_name, quoted_sheet_name } }];

const plan = $('Resolve Plan Date').first().json;
const sheetRef = plan.quoted_sheet_name || `'${String(plan.sheet_name || '').replace(/'/g, "''")}'`;
const rows = $('Read Task List For Day').all().map(i => i.json);
const gridRaw = $('Read Daily Planner Grid').first().json || {};
const valueRanges = gridRaw.valueRanges || [];
const gridValues = (valueRanges[0] && valueRanges[0].values) || [];
const startRow = 15;
const activeStatuses = new Set(['⏳ Pending','🔄 In Progress','✋ On Hold','🛑 Delayed','⚠️ Overdue','🔍 Under Review']);
function toIso(value) {
  const s = String(value || '').trim();
  if (!s) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const us = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (us) return `${us[3]}-${String(us[1]).padStart(2, '0')}-${String(us[2]).padStart(2, '0')}`;
  return s;
}
function stripLabel(value) {
  return String(value || '').replace(/[^\p{L}\p{N}\s]/gu, ' ').replace(/\s+/g, ' ').trim().toLowerCase();
}
function parseDisplayMinutes(label) {
  const s = String(label || '').trim();
  const match = s.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
  if (!match) return null;
  let hour = parseInt(match[1], 10) % 12;
  const minute = parseInt(match[2], 10);
  if (String(match[3]).toUpperCase() === 'PM') hour += 12;
  return hour * 60 + minute;
}
function parseExplicitMinutes(text) {
  const s = String(text || '').trim();
  let match = s.match(/\b(1[0-2]|0?[1-9])(?::([0-5][0-9]))?\s*(AM|PM)\b/i);
  if (match) {
    let hour = parseInt(match[1], 10) % 12;
    const minute = parseInt(match[2] || '0', 10);
    if (String(match[3]).toUpperCase() === 'PM') hour += 12;
    return hour * 60 + minute;
  }
  match = s.match(/\b([01]?\d|2[0-3])[:.]([0-5][0-9])\b/);
  if (match) return parseInt(match[1], 10) * 60 + parseInt(match[2], 10);
  match = s.match(/\b([01]?\d|2[0-3])\b/);
  if (match) return parseInt(match[1], 10) * 60;
  return null;
}
function weekdayIndex(iso) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(String(iso || ''))) return null;
  return new Date(`${iso}T00:00:00Z`).getUTCDay();
}
const slots = [];
let rollover = 0;
let previousBaseMinutes = null;
for (let i = 0; i < gridValues.length; i++) {
  const rowVals = gridValues[i] || [];
  const label = String(rowVals[0] || '').trim();
  const baseMinutes = parseDisplayMinutes(label);
  if (baseMinutes !== null && previousBaseMinutes !== null && baseMinutes < previousBaseMinutes) rollover += 1440;
  if (baseMinutes !== null) previousBaseMinutes = baseMinutes;
  slots.push({
    row: startRow + i,
    label,
    minutes: baseMinutes === null ? null : baseMinutes + rollover,
    task: String(rowVals[1] || '').trim()
  });
}
const slotRows = slots.map(slot => slot.row);
const occupied = new Map(slots.map(slot => [slot.row, slot.task]));
function slotRowsBetween(minFrom, minTo) {
  return slots.filter(slot => slot.minutes !== null && slot.minutes >= minFrom && slot.minutes <= minTo).map(slot => slot.row);
}
function preferredRows(task) {
  const category = stripLabel(task['Category']);
  const track = stripLabel(task['Track']);
  const text = `${task['Task'] || ''} ${task['Notes'] || ''}`.toLowerCase();
  const explicitMinutes = parseExplicitMinutes(text);
  if (explicitMinutes !== null) {
    const normalized = explicitMinutes < 7 * 60 ? explicitMinutes + 1440 : explicitMinutes;
    const exact = slots.find(slot => slot.minutes === normalized);
    if (exact) return [exact.row];
    const nearest = slots
      .filter(slot => slot.minutes !== null)
      .sort((a, b) => Math.abs(a.minutes - normalized) - Math.abs(b.minutes - normalized))[0];
    return nearest ? [nearest.row] : [];
  }
  if (/(завтрак|breakfast|заряд|йога|медитац|утро|body|walk|пешкадрал|вода)/.test(text) || track === 'vitality' || category === 'health') {
    return [...slotRowsBetween(7 * 60, 9 * 60 + 30), ...slotRowsBetween(20 * 60, 22 * 60 + 30)];
  }
  if (/(обед|lunch|ужин|dinner|snack)/.test(text)) {
    return [...slotRowsBetween(12 * 60, 14 * 60), ...slotRowsBetween(18 * 60, 20 * 60)];
  }
  if (/(школ|клиент|контент|работ|career|business|education|meeting|созвон|звонок)/.test(text) || track === 'craft' || ['career','business','education','finances','finance','hobby'].includes(category)) {
    return slotRowsBetween(9 * 60, 18 * 60 + 30);
  }
  if (track === 'social' || ['social','family','friends','appointment','contact'].includes(category) || /(мама|подруг|семь|встреч|звон)/.test(text)) {
    return slotRowsBetween(16 * 60, 21 * 60 + 30);
  }
  if (/(batch cooking|cook|дом|household|уборк|посуд|готов)/.test(text) || category === 'household') {
    return slotRowsBetween(17 * 60, 21 * 60);
  }
  return slotRows.slice();
}
